mod tests {
    use super::*;

    #[test]
    fn test_compact_p256_signature() {
        let sig = PasskeySignature::P256(P256Signature::new(
            FixedBytes::from([1u8; 64]),
            FixedBytes::from([2u8; 64]),
        ));

        let mut buf = Vec::new();
        let _len = sig.to_compact(&mut buf);

        let (decoded, remaining) = PasskeySignature::from_compact(&buf, 0);
        assert!(remaining.is_empty());
        assert_eq!(sig, decoded);
    }

